// ═══ utils.js ═══
// ── UTILS ──────────────────────────────────────────────────────────────────
// Pure helper functions. No DOM access, no state mutation, no API calls.
// Safe to unit-test independently. Add helpers here freely.

/** Format a large number: 1234567 → "1.2M", 12345 → "12k" */
function fK(n) {
  if (n == null) return '—';
  if (n >= 1e6)  return (n / 1e6).toFixed(1) + 'M';
  if (n >= 1000) return Math.round(n / 1000) + 'k';
  return Math.round(n) + '';
}

/** Format seconds as human duration: 3700 → "1h1m", 90000 → "1d" */
function fA(s) {
  if (s == null) return '—';
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  if (h >= 48) return Math.floor(h / 24) + 'd';
  if (h > 0)   return h + 'h' + m + 'm';
  return m + 'm';
}

/** CSS class name for intel age colour: fresh=green, old=red */
function aC(s) {
  if (s == null) return 'wao';
  const h = s / 3600;
  if (h < 1)  return 'waf';
  if (h < 4)  return 'was';
  if (h < 12) return 'waw';
  return 'wao';
}

/** NW range check: can attacker NW a hit target NW? (75–133% rule) */
function canHit(attackerNW, targetNW) {
  const r = attackerNW / targetNW;
  return r >= 0.75 && r <= 1.33;
}

/** HTML-escape a string to prevent XSS in innerHTML strings */
function esc(s) {
  return (s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;')
                  .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

/**
 * Look up the live enemy province object for a card's slot string.
 * slot may be "[18]" or 18 — normalised inside.
 */
function pd(slot) {
  if (!S.enemy) return null;
  const n = parseInt((slot + '').replace(/\[|\]/g, ''));
  return S.enemy.provinces.find(p => p.slot === n);
}

/** Shorthand for document.getElementById */
function $id(id) {
  return document.getElementById(id);
}

/** Update the save status indicator in the header */
function setSav(msg, cls) {
  const el = $id('__wpsav');
  if (el) {
    el.textContent = msg;
    el.className = 'wsav' + (cls ? ' ' + cls : '');
  }
}

/**
 * Safely render a tab content area.
 * Wraps the render function in try/catch so one broken tab can't crash others.
 * @param {string} elId  — DOM id of the tab content div
 * @param {Function} fn  — function that returns an HTML string
 */
function renderTab(elId, fn) {
  const el = $id(elId);
  if (!el) return;
  try {
    el.innerHTML = fn();
  } catch (e) {
    el.innerHTML = `<div class="wload" style="color:#ff4455">
      RENDER ERROR: ${esc(e.message)}<br>
      <span style="font-size:10px;color:#4a6a88">${esc(e.stack ? e.stack.split('\n')[1] : '')}</span>
    </div>`;
    console.error('[WavePlanner] render error in', elId, e);
  }
}

/** Loading spinner HTML — used while async data is in-flight */
function loadingHTML(msg) {
  return `<div class="wload"><div class="wspin"></div>${esc(msg || 'LOADING...')}</div>`;
}

/** Section heading HTML used in multiple tabs */
function sectionHead(label) {
  return `<div class="wsech">${esc(label)}</div>`;
}


// ═══ api.js ═══
// ── API ────────────────────────────────────────────────────────────────────
// All calls to api.intel.utopia.site live here.
// Functions are async and return parsed data or throw on failure.
// This is the only place that knows about BASE and H — add new endpoints here.

function _headers() {
  return { 'Utopia-Token': S.token, 'Content-Type': 'application/json' };
}

function _url(path) {
  return `${CFG.API_BASE}${path}`;
}

/** Fetch own kingdom data (SoT, SoM, SoS, Survey per province) */
async function fetchOwnKingdom() {
  const r = await fetch(_url(`/Kingdom/v1/OwnKingdom?server=${S.server}`), { headers: _headers() });
  if (!r.ok) throw new Error(`API ${r.status} — token may be expired. Reload the IS via game link.`);
  return r.json();
}

/** Fetch enemy kingdom data */
async function fetchEnemyKingdom(location) {
  const r = await fetch(_url(`/Kingdom/v1/EnemyKingdom?server=${S.server}&location=${location}`), { headers: _headers() })
    .catch(() => null);
  if (!r || !r.ok) return null;
  return r.json();
}

/** Fetch all op logs for the own kingdom (~24h window) */
async function fetchKingdomOps() {
  const r = await fetch(_url(`/Kingdom/v1/KingdomOps?server=${S.server}`), { headers: _headers() })
    .catch(() => null);
  if (!r || !r.ok) return null;
  return r.json();
}

/**
 * Create or update a war plan.
 * Pass an empty body {} to just get/create the warPlanId.
 * Pass {json, warPlanId} to save content.
 */
async function postWarPlan(location, body) {
  const r = await fetch(_url(`/WarPlan/v1/Post?server=${S.server}&location=${location}`), {
    method: 'POST',
    headers: _headers(),
    body: JSON.stringify(body || {}),
  });
  if (!r.ok) return null;
  return r.json();
}

/** Load a saved war plan by ID */
async function getWarPlan(location, warPlanId) {
  const r = await fetch(_url(`/WarPlan/v1/Get?server=${S.server}&location=${location}&warPlanId=${warPlanId}`), {
    headers: _headers(),
  });
  if (!r.ok) return null;
  return r.json();
}


// ═══ firebase.js ═══
// ── FIREBASE ───────────────────────────────────────────────────────────────
// Firestore REST API helpers. No SDK required — plain fetch.
// All functions return parsed JS objects, not raw Firestore field maps.

/** Convert a plain JS value to a Firestore field value */
function _toFB(v) {
  if (v === null || v === undefined) return { nullValue: null };
  if (typeof v === 'boolean') return { booleanValue: v };
  if (typeof v === 'number')  return Number.isInteger(v) ? { integerValue: String(v) } : { doubleValue: v };
  if (typeof v === 'string')  return { stringValue: v };
  if (v instanceof Set)       return { arrayValue: { values: [...v].map(_toFB) } };
  if (Array.isArray(v))       return { arrayValue: { values: v.map(_toFB) } };
  if (typeof v === 'object')  return { mapValue: { fields: Object.fromEntries(Object.entries(v).map(([k, val]) => [k, _toFB(val)])) } };
  return { stringValue: String(v) };
}

/** Convert a Firestore field value back to a plain JS value */
function _fromFB(v) {
  if (!v) return null;
  if ('stringValue'  in v) return v.stringValue;
  if ('integerValue' in v) return parseInt(v.integerValue);
  if ('doubleValue'  in v) return v.doubleValue;
  if ('booleanValue' in v) return v.booleanValue;
  if ('arrayValue'   in v) return (v.arrayValue.values || []).map(_fromFB);
  if ('mapValue'     in v) return Object.fromEntries(Object.entries(v.mapValue.fields || {}).map(([k, val]) => [k, _fromFB(val)]));
  return null;
}

function _fbUrl(path) {
  return `${CFG.FB_BASE}/${path}?key=${CFG.FB_API_KEY}`;
}

/** Write (PATCH/upsert) a document at path with plain JS data object */
async function fbWrite(path, data) {
  const fields = Object.fromEntries(Object.entries(data).map(([k, v]) => [k, _toFB(v)]));
  const r = await fetch(_fbUrl(path), {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ fields }),
  }).catch(() => null);
  if (!r) return null;
  return r.json();
}

/** Read a single document at path, returns plain JS object or null */
async function fbGet(path) {
  const r = await fetch(_fbUrl(path)).catch(() => null);
  if (!r || !r.ok) return null;
  return r.json();
}

/**
 * Query a collection with simple field filters.
 * filters: [{field, op, value}] — op defaults to 'EQUAL', value must be a string.
 * Returns array of plain JS objects (fields unwrapped from Firestore format).
 */
/** Delete a document at path */
async function fbDelete(path) {
  const r = await fetch(_fbUrl(path), { method: 'DELETE' }).catch(() => null);
  return r?.ok || false;
}

async function fbQuery(collection, filters = []) {
  const url = `${CFG.FB_BASE}:runQuery?key=${CFG.FB_API_KEY}`;
  const where = filters.map(f => ({
    fieldFilter: {
      field: { fieldPath: f.field },
      op: f.op || 'EQUAL',
      value: { stringValue: f.value },
    },
  }));
  const body = {
    structuredQuery: {
      from: [{ collectionId: collection }],
      where: filters.length === 1 ? where[0] : { compositeFilter: { op: 'AND', filters: where } },
      limit: 2000,
    },
  };
  const r = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  }).catch(() => null);
  if (!r || !r.ok) return [];
  const data = await r.json();
  return (data || [])
    .filter(d => d.document)
    .map(d => Object.fromEntries(Object.entries(d.document.fields || {}).map(([k, v]) => [k, _fromFB(v)])));
}


